# Supabase Buckets Setup Verification Script
# Usage: .\verify-buckets.ps1

Write-Host \"🔍 SalesAPE Storage Buckets Verification\" -ForegroundColor Cyan\nWrite-Host \"========================================\" -ForegroundColor Cyan\nWrite-Host \"\"\n\n# Check if .env file exists\n$envPath = \"app/backend/.env\"\nif (-Not (Test-Path $envPath)) {\n    Write-Host \"❌ Backend .env file not found at $envPath\" -ForegroundColor Red\n    Write-Host \"   Create one by copying .env.example\" -ForegroundColor Yellow\n    exit 1\n}\n\nWrite-Host \"✅ Backend .env file found\" -ForegroundColor Green\n\n# Check required environment variables\n$supabaseUrl = Get-Content $envPath | Select-String \"SUPABASE_URL\" | ForEach-Object { $_.ToString().Split('=')[1] }\n$supabaseKey = Get-Content $envPath | Select-String \"SUPABASE_SERVICE_KEY\" | ForEach-Object { $_.ToString().Split('=')[1] }\n\nif (-Not $supabaseUrl -or -Not $supabaseKey) {\n    Write-Host \"❌ Missing SUPABASE_URL or SUPABASE_SERVICE_KEY in .env\" -ForegroundColor Red\n    Write-Host \"   Add these variables to app/backend/.env\" -ForegroundColor Yellow\n    exit 1\n}\n\nWrite-Host \"✅ Supabase credentials configured\" -ForegroundColor Green\nWrite-Host \"   URL: $($supabaseUrl.Substring(0, 20))...\" -ForegroundColor Gray\n\n# Check if Node.js is installed\nif (-Not (Get-Command \"node\" -ErrorAction SilentlyContinue)) {\n    Write-Host \"❌ Node.js not found - required for testing\" -ForegroundColor Red\n    exit 1\n}\n\nWrite-Host \"✅ Node.js installed\" -ForegroundColor Green\n\n# Check if npm dependencies are installed\nif (-Not (Test-Path \"app/backend/node_modules\")) {\n    Write-Host \"❌ Dependencies not installed\" -ForegroundColor Red\n    Write-Host \"   Run: cd app/backend && npm install\" -ForegroundColor Yellow\n    exit 1\n}\n\nWrite-Host \"✅ Dependencies installed\" -ForegroundColor Green\n\n# Create a simple test script\n$testScript = @\"\nimport { createClient } from '@supabase/supabase-js';\n\nconst SUPABASE_URL = process.env.SUPABASE_URL;\nconst SUPABASE_SERVICE_KEY = process.env.SUPABASE_SERVICE_KEY;\n\nconst supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_KEY);\n\nconst buckets = ['websites', 'videos', 'audio', 'generated-assets'];\n\nasync function testBuckets() {\n  try {\n    const { data, error } = await supabase.storage.listBuckets();\n    \n    if (error) {\n      console.error('❌ Could not connect to Supabase:', error.message);\n      process.exit(1);\n    }\n    \n    console.log('✅ Connected to Supabase');\n    console.log('\\nExisting buckets:');\n    \n    const existingNames = data.map(b => b.name);\n    buckets.forEach(name => {\n      if (existingNames.includes(name)) {\n        console.log(`  ✅ ${name}`);\n      } else {\n        console.log(`  ❌ ${name} (MISSING)`);\n      }\n    });\n    \n    const allExist = buckets.every(name => existingNames.includes(name));\n    \n    if (allExist) {\n      console.log('\\n✅ All required buckets exist!');\n      process.exit(0);\n    } else {\n      console.log('\\n❌ Some buckets are missing. See SUPABASE_BUCKETS_SETUP.md for instructions.');\n      process.exit(1);\n    }\n  } catch (err) {\n    console.error('❌ Error:', err.message);\n    process.exit(1);\n  }\n}\n\ntestBuckets();\n\"@\n\n# Write test script to temp file\n$tempScript = \"temp-bucket-test.mjs\"\n$testScript | Out-File -FilePath $tempScript -Encoding UTF8\n\nWrite-Host \"\"\nWrite-Host \"🔧 Testing Supabase bucket access...\" -ForegroundColor Cyan\n\n# Run test\ncd app/backend\nnode ../../$tempScript\n\n$testResult = $LASTEXITCODE\n\n# Cleanup\ncd ../..\nRemove-Item $tempScript -ErrorAction SilentlyContinue\n\nif ($testResult -eq 0) {\n    Write-Host \"\"\n    Write-Host \"🎉 Setup verification complete!\" -ForegroundColor Green\n    Write-Host \"You're ready to start using SalesAPE.\" -ForegroundColor Green\n} else {\n    Write-Host \"\"\n    Write-Host \"⚠️  Some buckets may be missing.\" -ForegroundColor Yellow\n    Write-Host \"Follow the setup guide: SUPABASE_BUCKETS_SETUP.md\" -ForegroundColor Yellow\n}\n\nexit $testResult\n